    // D. TRIGGER THE RESPONSE
    googleSocket.send(JSON.stringify({
      client_content: {
        turns: [{ role: "user", parts: [{ text: "I have sent you the visuals and the audio. What is happening in the video?" }] }],
        turn_complete: true
      }
    }));

  } catch (err) {
    console.error("--- [SHOVEL ERROR] ---", err);
  }
}

